// Package ecdsa implements ECDSA signature, suitable for OpenPGP,// as specified in RFC 6637, section 5.package ecdsaimport ("errors""github.com/ProtonMail/go-crypto/openpgp/internal/ecc""io""math/big")type PublicKey struct {X, Y  *big.Intcurve ecc.ECDSACurve}type PrivateKey struct {PublicKeyD *big.Int}PublicKey(curve ecc.ECDSACurve) *PublicKey {return &PublicKey{curve: curve,}}PrivateKey(key PublicKey) *PrivateKey {return &PrivateKey{PublicKey: key,}} *PublicKey) GetCurve() ecc.ECDSACurve {return pk.curve} *PublicKey) MarshalPoint() []byte {return pk.curve.MarshalIntegerPoint(pk.X, pk.Y)} *PublicKey) UnmarshalPoint(p []byte) error {pk.X, pk.Y = pk.curve.UnmarshalIntegerPoint(p)if pk.X == nil {return errors.New("ecdsa: failed to parse EC point")}return nil} *PrivateKey) MarshalIntegerSecret() []byte {return sk.curve.MarshalIntegerSecret(sk.D)} *PrivateKey) UnmarshalIntegerSecret(d []byte) error {sk.D = sk.curve.UnmarshalIntegerSecret(d)if sk.D == nil {return errors.New("ecdsa: failed to parse scalar")}return nil}erateKey(rand io.Reader, c ecc.ECDSACurve) (priv *PrivateKey, err error) {priv = new(PrivateKey)priv.PublicKey.curve = cpriv.PublicKey.X, priv.PublicKey.Y, priv.D, err = c.GenerateECDSA(rand)return}n(rand io.Reader, priv *PrivateKey, hash []byte) (r, s *big.Int, err error) {return priv.PublicKey.curve.Sign(rand, priv.X, priv.Y, priv.D, hash)}ify(pub *PublicKey, hash []byte, r, s *big.Int) bool {return pub.curve.Verify(pub.X, pub.Y, hash, r, s)}idate(priv *PrivateKey) error {return priv.curve.ValidateECDSA(priv.X, priv.Y, priv.D.Bytes())}